async function uploadWithBgFetch(file, reg, progressInner, status) {
  const fetchId = `upload-${file.name}-${Date.now()}`;
  const formData = new FormData();
  formData.append('file', file);

  try {
    const bgFetch = await reg.backgroundFetch.fetch(
      fetchId,
      [new Request('/upload', { method: 'POST', body: formData })],
      { title: `Uploading ${file.name}`, uploadTotal: file.size }
    );

    bgFetchMap.set(fetchId, { progressInner, status });
    status.textContent = 'Uploading (background-safe)...';

    bgFetch.addEventListener('progress', () => {
      if (!bgFetch.uploadTotal) return;
      const pct = Math.round((bgFetch.uploaded / bgFetch.uploadTotal) * 100);
      progressInner.style.width = pct + '%';
      status.textContent = `Uploading... ${pct}%`;
    });
  } catch (err) {
    // Fall back to XHR if background fetch init fails
    console.warn('Background fetch failed to start, falling back to XHR:', err);
    uploadWithXhr(file, progressInner, status);
  }
}

function uploadWithXhr(file, progressInner, status) {
  const formData = new FormData();
  formData.append('file', file);

  const xhr = new XMLHttpRequest();
  xhr.open('POST', '/upload', true);

  xhr.upload.onprogress = function(e) {
    if (e.lengthComputable) {
      const pct = Math.round((e.loaded / e.total) * 100);
      progressInner.style.width = pct + '%';
      status.textContent = `Uploading... ${pct}%`;
    }
  };

  xhr.onload = function() {
    if (xhr.status === 200) {
      status.textContent = '✅ Uploaded Successfully';
    } else {
      status.textContent = '❌ Upload Failed';
      progressInner.style.backgroundColor = 'red';
    }
  };

  xhr.onerror = function() {
    status.textContent = '❌ Upload Failed (Network)';
    progressInner.style.backgroundColor = 'red';
  };

  xhr.send(formData);
}

