async function uploadFiles() {
  const files = document.getElementById('fileInput').files;
  const container = document.getElementById('progress-container');
  const note = document.getElementById('bg-fetch-note');

  const reg = swRegistration || (await navigator.serviceWorker.ready.catch(() => null));
  const useBgFetch = reg && 'backgroundFetch' in reg;

  note.textContent = useBgFetch
    ? '📡 Background uploads active — safe to lock screen or switch apps'
    : '⚠️ Background Fetch not supported — keep this tab open during upload';

  const metadata = Array.from(files).map(f => ({ filename: f.name, size: f.size }));
  let toUpload = new Set(metadata.map(f => f.filename));
  try {
    const res = await fetch('/check-existing', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(metadata),
    });
    const data = await res.json();
    toUpload = new Set(data.to_upload);

    for (const name of data.skipped) {
      const fileBlock = document.createElement('div');
      fileBlock.className = 'file-upload';
      fileBlock.innerHTML = `<div>${name}</div><div class="status">⏭️ Already exists — skipped</div>`;
      container.appendChild(fileBlock);
    }
  } catch (e) {
    console.warn('check-existing failed, uploading all:', e);
  }

  const executing = new Set();

  for (let i = 0; i < files.length; i++) {
    const file = files[i];
    if (!toUpload.has(file.name)) continue;

    const fileBlock = document.createElement('div');
    fileBlock.className = 'file-upload';

    const title = document.createElement('div');
    title.textContent = file.name;

    const progressBar = document.createElement('div');
    progressBar.className = 'progress-bar';

    const progressInner = document.createElement('div');
    progressInner.className = 'progress-bar-inner';
    progressBar.appendChild(progressInner);

    const status = document.createElement('div');
    status.className = 'status';
    status.textContent = 'Queued...';

    fileBlock.appendChild(title);
    fileBlock.appendChild(progressBar);
    fileBlock.appendChild(status);
    container.appendChild(fileBlock);

    const uploadFn = useBgFetch
      ? () => uploadWithBgFetch(file, reg, progressInner, status)
      : () => uploadWithXhr(file, progressInner, status);

    const p = uploadFn().finally(() => executing.delete(p));
    executing.add(p);

    if (executing.size >= MAX_CONCURRENT) {
      await Promise.race(executing);
    }
  }

  await Promise.all(executing);
}

